以下是针对微信文章标题提取与图片处理的完整解决方案：

```python
import requests
from bs4 import BeautifulSoup
import os
from urllib.parse import urljoin

def parse_wechat_article(url):
    """结构化解析微信文章"""
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36'
    }

    result = {
        'main_title': '',
        'sub_titles': [],
        'content': [],
        'images': []
    }

    try:
        response = requests.get(url, headers=headers, timeout=10)
        soup = BeautifulSoup(response.text, 'html.parser')

        # 提取主标题（H1级）
        main_title = soup.find('h1', class_='rich_media_title')
        if main_title:
            result['main_title'] = main_title.get_text(strip=True)

        # 提取子标题（H2级）
        for h2 in soup.find_all(['h2', 'h3'], class_='rich_media_title'):
            result['sub_titles'].append({
                'level': h2.name,  # h2 或 h3
                'text': h2.get_text(strip=True)
            })

        # 解析正文内容和图片
        content_div = soup.find('div', class_='rich_media_content')
        if content_div:
            for element in content_div.children:
                # 段落处理
                if element.name == 'p':
                    result['content'].append({
                        'type': 'text',
                        'data': element.get_text(strip=True)
                    })

                # 图片处理（含懒加载）
                elif element.name == 'img':
                    img_data = {
                        'src': element.get('data-src') or element.get('src'),
                        'alt': element.get('alt', ''),
                        'width': element.get('data-w'),
                        'height': element.get('data-ratio')
                    }
                    if img_data['src']:
                        # 转换为绝对URL
                        img_data['src'] = urljoin(url, img_data['src'])
                        result['images'].append(img_data)
                        result['content'].append({
                            'type': 'image',
                            'data': img_data
                        })

        return result

    except Exception as e:
        return {'error': str(e)}

def download_images(article_data, save_folder='wechat_images'):
    """下载文章图片到本地"""
    if not os.path.exists(save_folder):
        os.makedirs(save_folder)

    downloaded = []
    for idx, img in enumerate(article_data['images']):
        try:
            response = requests.get(img['src'], stream=True, timeout=10)
            if response.status_code == 200:
                # 生成唯一文件名
                filename = f"{article_data['main_title'][:20]}_{idx}.jpg"
                filepath = os.path.join(save_folder, filename)

                with open(filepath, 'wb') as f:
                    for chunk in response.iter_content(1024):
                        f.write(chunk)
                downloaded.append(filepath)
        except Exception as e:
            print(f"图片下载失败：{img['src']} - {str(e)}")

    return downloaded

# 使用示例
if __name__ == "__main__":
    article_url = "您的文章URL"
    article_data = parse_wechat_article(article_url)

    if 'error' not in article_data:
        # 打印结构化数据
        print(f"主标题：{article_data['main_title']}")
        print("\n子标题：")
        for sub in article_data['sub_titles']:
            print(f"{'#' * int(sub['level'][1:])} {sub['text']}")  # 转换为Markdown格式

        print("\n下载图片...")
        downloaded_files = download_images(article_data)
        print(f"已下载 {len(downloaded_files)} 张图片")
    else:
        print(f"解析失败：{article_data['error']}")
```

### 方案特点说明：

1. **标题分级系统**：
- 主标题自动识别为`<h1 class="rich_media_title">`
- 子标题智能匹配`<h2>`/`<h3>`标签并保留层级信息
- 输出数据包含标题级别信息（h1/h2/h3）

2. **图片处理机制**：
- 自动处理微信的懒加载图片（优先获取data-src属性）
- 支持相对路径转绝对路径
- 可选图片下载功能（默认保存为JPG格式）

3. **内容结构保存**：
- 正文内容按段落和图片顺序保存
- 输出结构：
  ```json
  {
    "main_title": "主标题",
    "sub_titles": [
      {"level": "h2", "text": "子标题1"},
      {"level": "h3", "text": "子标题2"}
    ],
    "content": [
      {"type": "text", "data": "段落内容"},
      {"type": "image", "data": {"src": "...", "alt": "..."}}
    ],
    "images": [
      {"src": "图片URL", "alt": "描述文本", ...}
    ]
  }
  ```

### 注意事项：

1. **图片保存限制**：
   - 微信图片可能有防盗链措施，建议：
     - 使用`Referer`请求头：`headers['Referer'] = 'https://mp.weixin.qq.com/'`
     - 或者使用无头浏览器（如Selenium）加载

2. **动态加载内容**：
   - 如果遇到无法获取内容的情况，可能需要：
   ```python
   from selenium import webdriver

   def get_dynamic_page(url):
       driver = webdriver.Chrome()
       driver.get(url)
       html = driver.page_source
       driver.quit()
       return html
   ```

3. **法律合规性**：
   - 下载的图片仅可用于个人学习研究
   - 如需商用，必须获得版权方授权
   - 建议添加使用声明：
     ```python
     print("本工具获取内容仅用于技术研究，请于24小时内删除下载内容")
     ```

如果需要将结果转换为微信原文格式，可以添加以下转换函数：

```python
def to_markdown(article_data):
    """转换为Markdown格式"""
    md = []
    md.append(f"# {article_data['main_title']}\n")

    for sub in article_data['sub_titles']:
        md.append(f"{'#' * (int(sub['level'][1:])+1)} {sub['text']}\n")

    for item in article_data['content']:
        if item['type'] == 'text':
            md.append(f"{item['data']}\n")
        elif item['type'] == 'image':
            md.append(f"![{item['data']['alt']}]({item['data']['src']})\n")

    return '\n'.join(md)
